import React, { useState, useEffect } from 'react';
import { Link } from 'react-router-dom';
import B2BProductCard from '../components/B2BProductCard';

const Home = () => {
  const [bikes, setBikes] = useState([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    fetchBikes();
  }, []);

  const fetchBikes = async () => {
    try {
      const response = await fetch('http://localhost:5002/api/bikes');
      const result = await response.json();
      if (result.success) {
        setBikes(result.data);
      }
    } catch (error) {
      console.error('Error fetching bikes:', error);
    } finally {
      setLoading(false);
    }
  };

  const formatPrice = (price) => new Intl.NumberFormat('en-IN').format(price);

  const manufacturers = [
    { name: 'Bajaj Auto', country: 'India', logo: '🏭', listings: 45, verified: true },
    { name: 'Royal Enfield', country: 'India', logo: '👑', listings: 62, verified: true },
    { name: 'Yamaha Motor', country: 'Japan', logo: '🎵', listings: 38, verified: true },
    { name: 'KTM India', country: 'Austria', logo: '🔶', listings: 28, verified: true },
    { name: 'Kawasaki', country: 'Japan', logo: '🟢', listings: 22, verified: true },
    { name: 'Honda Motor', country: 'Japan', logo: '🔴', listings: 55, verified: true },
  ];

  const benefits = [
    { icon: '🔒', title: 'Secure Bulk Transactions', desc: 'End-to-end encrypted payments with escrow protection for every wholesale order.' },
    { icon: '✅', title: 'Verified Suppliers', desc: 'Every manufacturer and dealer is KYC verified and audited for quality assurance.' },
    { icon: '🚚', title: 'Logistics Support', desc: 'Integrated pan-India logistics with real-time tracking for bulk shipments.' },
    { icon: '🏭', title: 'Direct Manufacturer Access', desc: 'Connect directly with OEMs, eliminating middlemen and reducing costs.' },
    { icon: '💰', title: 'Transparent Pricing', desc: 'Real-time market prices with volume discounts. No hidden charges ever.' },
    { icon: '📊', title: 'Dealer Dashboard', desc: 'Comprehensive analytics, order management, and inventory control in one place.' },
  ];

  const trendingCategories = [
    { name: 'Sports Bikes', demand: '+24%', volume: '1,240' },
    { name: 'Cruiser Bikes', demand: '+18%', volume: '980' },
    { name: 'Adventure', demand: '+32%', volume: '650' },
    { name: 'Commuter', demand: '+8%', volume: '2,100' },
  ];

  const recentlyAdded = [
    { name: 'KTM RC 390 2026', price: '₹3,85,000', date: 'Today' },
    { name: 'Himalayan 450 Rally', price: '₹3,10,000', date: 'Yesterday' },
    { name: 'Ninja 300 ABS', price: '₹3,35,000', date: '2 days ago' },
    { name: 'Classic 350 Reborn', price: '₹2,05,000', date: '3 days ago' },
  ];

  const bulkDemands = [
    { name: 'NS 200 × 50 units', dealer: 'Metro Motors, Delhi', status: 'Open' },
    { name: 'Classic 350 × 30 units', dealer: 'Royal Rides, Mumbai', status: 'Open' },
    { name: 'MT 15 × 25 units', dealer: 'Speed Hub, Bangalore', status: 'Matched' },
    { name: 'Duke 200 × 40 units', dealer: 'KTM Zone, Pune', status: 'Open' },
  ];

  return (
    <div>
      {/* ═══════ SECTION 1: HERO + LIVE BIKES ═══════ */}
      <div className="hero-section">
        {/* 3D Background Video — slow + light */}
        <video
          className="hero-bg-video"
          autoPlay
          muted
          loop
          playsInline
          onLoadedData={(e) => { e.target.playbackRate = 0.4; }}
          src={`${process.env.PUBLIC_URL}/bikes/hero-video.mp4`}
        />

        <div className="hero-content">
          <div className="hero-tag">
            <span className="hero-tag-dot"></span>
            India's #1 B2B Bike Platform
          </div>

          <h1 className="hero-title">
            India's Leading <span>B2B Bike Trading</span> Platform
          </h1>

          <p className="hero-subtitle">
            Connect with verified manufacturers and dealers. Buy & sell bikes in bulk
            with transparent pricing, secure transactions, and pan-India logistics support.
          </p>

          <div className="hero-buttons">
            <Link to="/inventory" className="btn btn-primary btn-lg">
              📦 Explore Inventory
            </Link>
            <Link to="/dealers" className="btn btn-secondary btn-lg">
              🤝 Become a Dealer
            </Link>
          </div>

          <div className="hero-stats">
            <div className="hero-stat">
              <div className="hero-stat-value">2,500+</div>
              <div className="hero-stat-label">Bikes Listed</div>
            </div>
            <div className="hero-stat">
              <div className="hero-stat-value">180+</div>
              <div className="hero-stat-label">Verified Dealers</div>
            </div>
            <div className="hero-stat">
              <div className="hero-stat-value">₹45Cr+</div>
              <div className="hero-stat-label">Trade Volume</div>
            </div>
          </div>
        </div>

        {/* Live Bikes Grid */}
        <div className="hero-bikes-grid">
          {loading ? (
            <div className="loading" style={{ gridColumn: '1/-1' }}>
              <div className="spinner"></div>
            </div>
          ) : (
            bikes.slice(0, 4).map(bike => (
              <B2BProductCard key={bike.id} bike={bike} />
            ))
          )}
        </div>
      </div>

      {/* ═══════ SECTION 2: FEATURED MANUFACTURERS ═══════ */}
      <div style={{ marginBottom: '4rem' }}>
        <div className="section-header">
          <div className="section-tag">Trusted Partners</div>
          <h2 className="section-title">Featured Manufacturers</h2>
          <p className="section-desc">Partnered with India's top motorcycle brands for direct bulk procurement</p>
        </div>

        <div className="manufacturers-grid">
          {manufacturers.map((mfg, i) => (
            <div className="manufacturer-card" key={i}>
              <div className="manufacturer-logo">{mfg.logo}</div>
              <div className="manufacturer-name">{mfg.name}</div>
              <div className="manufacturer-country">{mfg.country} {mfg.verified && '✓'}</div>
              <div className="manufacturer-listings">{mfg.listings} Active Listings</div>
            </div>
          ))}
        </div>
      </div>

      {/* ═══════ SECTION 3: WHY CHOOSE US ═══════ */}
      <div style={{ marginBottom: '4rem' }}>
        <div className="section-header">
          <div className="section-tag">B2B Advantages</div>
          <h2 className="section-title">Why Choose BikesZone</h2>
          <p className="section-desc">Enterprise-grade features built for serious bike traders</p>
        </div>

        <div className="benefits-grid">
          {benefits.map((b, i) => (
            <div className="benefit-card" key={i}>
              <div className="benefit-icon">{b.icon}</div>
              <div className="benefit-title">{b.title}</div>
              <div className="benefit-desc">{b.desc}</div>
            </div>
          ))}
        </div>
      </div>

      {/* ═══════ SECTION 4: MARKET INSIGHTS ═══════ */}
      <div style={{ marginBottom: '4rem' }}>
        <div className="section-header">
          <div className="section-tag">Live Data</div>
          <h2 className="section-title">Market Insights</h2>
          <p className="section-desc">Real-time market intelligence for smarter trading decisions</p>
        </div>

        <div className="insights-grid">
          <div className="insight-card">
            <div className="insight-card-header">
              <div className="insight-card-title">📈 Trending Categories</div>
            </div>
            {trendingCategories.map((c, i) => (
              <div className="insight-item" key={i}>
                <span className="insight-item-name">{c.name}</span>
                <span className="insight-item-value" style={{ color: '#10b981' }}>{c.demand}</span>
              </div>
            ))}
          </div>

          <div className="insight-card">
            <div className="insight-card-header">
              <div className="insight-card-title">🆕 Recently Added</div>
            </div>
            {recentlyAdded.map((r, i) => (
              <div className="insight-item" key={i}>
                <span className="insight-item-name">{r.name}</span>
                <span className="insight-item-value">{r.price}</span>
              </div>
            ))}
          </div>

          <div className="insight-card">
            <div className="insight-card-header">
              <div className="insight-card-title">🔥 Bulk Demands</div>
            </div>
            {bulkDemands.map((d, i) => (
              <div className="insight-item" key={i}>
                <span className="insight-item-name">{d.name}</span>
                <span className={`badge badge--${d.status === 'Open' ? 'success' : 'info'}`}>
                  <span className="badge-dot"></span>
                  {d.status}
                </span>
              </div>
            ))}
          </div>
        </div>
      </div>

      {/* ═══════ SECTION 5: CTA ═══════ */}
      <div className="cta-section">
        <h2 className="cta-title">Start Buying or Selling in Bulk Today</h2>
        <p className="cta-desc">
          Join 180+ verified dealers and manufacturers on India's fastest growing B2B bike marketplace.
        </p>
        <div className="cta-buttons">
          <Link to="/inventory" className="btn btn-white btn-lg">
            🏍️ Browse Inventory
          </Link>
          <Link to="/dealers" className="btn btn-white-outline btn-lg">
            📋 Register as Dealer
          </Link>
        </div>
      </div>
    </div>
  );
};

export default Home;
